import Foundation

enum FetchError: Error {
    case networkFailure
}

func fetchWithFallback(shouldFail: Bool) -> String {
    if shouldFail {
        return "Cached data"
    }
    return "Fresh data"
}

let result1 = fetchWithFallback(shouldFail: true)
let result2 = fetchWithFallback(shouldFail: false)
print("\(result1), \(result2)")

